module bin_to_gray(
    input [7:0] obf_binary,
    output reg [7:0] gray
);

always @(*) begin
    gray[7] = obf_binary[7];
    gray[6] = obf_binary[7] ^ obf_binary[6];
    gray[5] = obf_binary[6] ^ obf_binary[5];
    gray[4] = obf_binary[5] ^ obf_binary[4];
    gray[3] = obf_binary[4] ^ obf_binary[3];
    gray[2] = obf_binary[3] ^ obf_binary[2];
    gray[1] = obf_binary[2] ^ obf_binary[1];
    gray[0] = obf_binary[1] ^ obf_binary[0];
end

endmodule
